commands.cmd:
out=$(find /etc /usr /var /tmp /opt -xdev -type d -perm -0002 -not -perm -1000 2>/dev/null)
rc=$?
[ $rc -eq 0 ] || [ -n "$out" ] || { echo "find produced no output and failed" >&2; exit 1; }
printf '%s\n' "$out" | awk '
  function esc(s){ gsub(/\\/,"\\\\",s); gsub(/"/,"\\\"",s); return s }
  BEGIN{ printf "{\"results\":["; sep="" }
  NF>0 {
    printf "%s{\"path\":\"%s\"}", sep, esc($0)
    sep=","
  }
  END{ printf "]}" }
'
